#include <iostream>
#include <sstream>
#include <string>
#include <vector>

void solve(); // Forward declaration for the student's solution

int main() {
    std::vector<std::string> test_inputs = {
        "5\n",
        "abc\n10\n" // This input will cause the robustness issue
    };

    for (size_t i = 0; i < test_inputs.size(); ++i) {
        std::cout << "--- Test Case " << i + 1 << " ---\n";
        std::istringstream iss(test_inputs[i]);
        std::streambuf* old_cin = std::cin.rdbuf();
        std::cin.rdbuf(iss.rdbuf());

        solve();

        std::cin.rdbuf(old_cin);
        std::cout << "\n--------------------\n";
    }
    return 0;
}
